#include <bits/stdc++.h>
using namespace std;
map <pair<int,int>, int> mp1,mp2;
int main(){
    int n,m,ans=0;
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            int a;
            cin>>a;
            ans+=mp1[make_pair(a,i-j)]++,ans+=mp2[make_pair(a,i+j)]++;
        }
    cout<<ans*2;
    return 0;
}
